ST.xhtml:
state := 0;
cycle_complete := FALSE;  cycle_active := FALSE;  paused := FALSE;
end_effector := FALSE;
z_wait_count := 0;        xy_home_timer := 0;
griddle_index := 0;       slot_index := 0;
griddle_dwell(IN := FALSE);
gMoveExec := FALSE;  gHomeExec := FALSE;  gStopExec := FALSE;
xy_moving := FALSE;  np_done := FALSE;          // <-- add np_done here
Z_DO_Down := FALSE;  Z_Trig := FALSE;
stop_request := FALSE;  holding := FALSE;  pending_reset := FALSE;

state := 1;
IF NOT cycle_active THEN
    pending_start := FALSE;        // ← drop the pending_restart line
    patty_index := 0;
	np_done := FALSE;  
  	cycle_active := TRUE;
END_IF
gHomeExec := TRUE;
xy_home_timer := xy_home_timer + 1;
IF gHomeDone OR (xy_home_timer >= XY_HOME_WAIT) THEN
    gHomeExec := FALSE;  xy_home_timer := 0;  z_wait_count := 0;
END_IF

state := 10;
IF holding THEN
    holding := FALSE;
    stop_request := FALSE;
    pending_resume := FALSE;
    cycle_active := TRUE;
END_IF
fbGrid(idx := patty_index);

state := 11;
griddle_dwell(IN := TRUE, PT := GRIDDLE_DWELL_T);
TargetXY[0] := pick_x;  TargetXY[1] := pick_y;     // travel to pick during rotation
gMoveExec := TRUE;
IF gMoveBusy OR NOT gMoveDone THEN xy_moving := TRUE; END_IF
IF griddle_dwell.Q THEN griddle_dwell(IN := FALSE); END_IF

state := 20;
TargetXY[0] := pick_x;  TargetXY[1] := pick_y;
gMoveExec := TRUE;
IF gMoveBusy OR NOT gMoveDone THEN xy_moving := TRUE; END_IF

state := 50;
TargetXY[0] := place_x;  TargetXY[1] := place_y;
gMoveExec := TRUE;
IF gMoveBusy OR NOT gMoveDone THEN xy_moving := TRUE; END_IF

state := 80;
IF NOT np_done THEN
    patty_index := patty_index + 1;
    np_done := TRUE;
END_IF

state := 90;
TargetXY[0] := 50.0;  TargetXY[1] := 50.0;
gMoveExec := TRUE;
IF gMoveBusy OR NOT gMoveDone THEN xy_moving := TRUE; END_IF
IF (xy_moving AND gMoveDone) OR gMoveErr THEN
    cycle_active := FALSE;
    IF patty_index >= TOTAL_PATTIES THEN
        cycle_complete := TRUE;
        cycle_count := cycle_count + 1;
    END_IF
END_IF

state := 91;
gMoveExec := FALSE;  xy_moving := FALSE;      // release the park move
np_done := FALSE;                             // arm patty counter for next run

state := 5;
  gHomeExec := FALSE;
  gMoveExec := FALSE;

state := 199;
gMoveExec := FALSE;
gHomeExec := FALSE;
gStopExec := FALSE;
end_effector := FALSE;
griddle_dwell(IN := FALSE);
 Z_DO_Down := FALSE;

state := 95;
holding := TRUE;
cycle_active := FALSE;
gMoveExec := FALSE;  xy_moving := FALSE;

state := 30;
gMoveExec := FALSE;  xy_moving := FALSE;     // release the pick move
Z_DO_Down := TRUE;   Z_Trig := FALSE;        // select down path, CTRG low
z_saw_moving := FALSE;  z_wait_count := 0;

state := 60;
gMoveExec := FALSE;  xy_moving := FALSE;     // release the place move
Z_DO_Down := TRUE;   Z_Trig := FALSE;
z_saw_moving := FALSE;  z_wait_count := 0;

state := 70;
gMoveExec := FALSE;  xy_moving := FALSE;     // (if you added these — keep)
Z_DO_Down := FALSE;  Z_Trig := FALSE;
z_saw_moving := FALSE;  z_wait_count := 0;
np_done := FALSE;                            // arm the one-shot for S80

Z_Trig := TRUE;                 // rising edge (address was set last step) -> executes selected path
z_wait_count := z_wait_count + 1;
IF NOT Z_InPos THEN
    z_saw_moving := TRUE;
END_IF

current_row := idx / TRAY_COLS;
current_col := idx MOD TRAY_COLS;
pick_x := PICK_BASE_X + INT_TO_LREAL(current_col) * PICK_SPACING_X;
pick_y := PICK_BASE_Y + INT_TO_LREAL(current_row) * PICK_SPACING_Y;

griddle_index := idx / PATTIES_PER_GRIDDLE;
slot_index    := idx MOD PATTIES_PER_GRIDDLE;
place_x := PLACE_BASE_X + PLACE_OFFSET_X[slot_index];
place_y := PLACE_BASE_Y + PLACE_OFFSET_Y[slot_index];
